];

const COMMUNES = {
  'cocody':['cocody','coco'], 'yopougon':['yopougon','yopo','yop'],
  'marcory':['marcory'], 'koumassi':['koumassi'],
  'treichville':['treichville','treich'], 'plateau':['plateau'],
  'adjame':['adjame'], 'abobo':['abobo'],
