function rangCommune(c) {
  if (!c) return 2;
  var cn = c.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');
  if (COMMUNES_CONNUES.some(function(k){ return cn.includes(k); })) return 0;
  return 1;
